import java.time.LocalDate;
import java.time.Period;

public class Main {
    public static void main(String[] args) {
        // 特定の日付を設定
        LocalDate date1 = LocalDate.of(2023, 5, 1);

        // 現在日付を取得
        LocalDate now = LocalDate.now();

        // 二つの日付の差分を計算
        Period diff = Period.between(now, date1);

        // 差分を日数で表示
        System.out.println(diff.getDays());
        // Expected output: "現在日付と2023-05-01との差分日数"
    }
}

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

public class Main {
    public static void main(String[] args) {
        // 特定の日付を設定
        LocalDate date = LocalDate.of(2023, 5, 1);

        // 日付のフォーマットを定義
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("d'th' MMMM, yyyy");

        // 日付を新しいフォーマットで表示
        System.out.println(date.format(formatter));
        // Expected output: "1st May, 2023"
    }
}

import java.time.LocalDate;

public class Main {
    public static void main(String[] args) {
        // 特定の日付を設定
        LocalDate date = LocalDate.of(2023, 5, 1);

        // 現在の日付を取得
        LocalDate currentDate = LocalDate.now();

        // 現在の日付が設定した日付より後であるかチェック
        if (currentDate.isAfter(date)) {
            System.out.println("The current date is after 2023-05-01");
            // Expected output: Depends on the current date
        } else {
            System.out.println("The current date is not after 2023-05-01");
            // Expected output: Depends on the current date
        }
    }
}

import java.time.LocalDate;

public class Main {
    public static void main(String[] args) {
        // 特定の日付を設定
        LocalDate date1 = LocalDate.of(2023, 5, 1);
        LocalDate date2 = LocalDate.of(2023, 6, 1);

        // 日付を比較
        if (date1.isBefore(date2)) {
            System.out.println(date1 + " is before " + date2);
            // Expected output: 2023-05-01 is before 2023-06-01
        } else if (date1.isAfter(date2)) {
            System.out.println(date1 + " is after " + date2);
        } else {
            System.out.println("Both dates are equal");
        }
    }
}
